$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '..')).Path;. (Join-Path $root 'tests/helpers/TypedStudioFixture.ps1');$work=Join-Path ([IO.Path]::GetTempPath()) ('context-role-'+[guid]::NewGuid().ToString('N'));New-Item -ItemType Directory $work|Out-Null
try{$p=New-TypedStudioFixture $work 'frontend' -Approved -ExistingRepository; & "$root/scripts/Resolve-SpecialistPlan.ps1" -ProjectRoot $p -OutputPath (Join-Path $p '.studio/reports/specialist-plan.json')|Out-Null;& "$root/scripts/context/compile_context.ps1" -ProjectRoot $p -Role frontend-builder|Out-Null;$m=Get-Content -Raw (Join-Path $p '.studio/runtime/context/frontend-builder.json')|ConvertFrom-Json;if($m.selectedRecords.path -match 'DATA_MODEL|OPERATIONS'){throw 'Frontend context contains excluded internals'};$empty=Join-Path $work 'empty';New-Item -ItemType Directory $empty|Out-Null;try{& "$root/scripts/context/compile_context.ps1" -ProjectRoot $empty -Role code-reviewer|Out-Null;throw 'Expected initialization block'}catch{if($_.Exception.Message -ne 'CONTEXT_PROJECT_NOT_INITIALIZED'){throw}};try{& "$root/scripts/context/compile_context.ps1" -ProjectRoot $p -Role frontend-builder -State implementation|Out-Null;throw 'Expected state conflict'}catch{if($_.Exception.Message -ne 'CONTEXT_STATE_CONFLICT'){throw}}}finally{Remove-Item $work -Recurse -Force};Write-Host 'Role-specific context assertions passed.'
